import { useEffect } from "react";
import { ShapeInPlaceProps } from "../../classes/shapeInPlace";
import { shapeList, Shapes } from "./shapes/Shape";
import { Color } from "three";
import { GameMode } from "../../interfaces/mode";

interface MinecraftProps{
    shapeInPlace: ShapeInPlaceProps,
    gameMode: GameMode
}

const Minecraft: React.FC<MinecraftProps> = ({
    shapeInPlace: {
        objects, addObject
    },
    gameMode
}) => {
    const opacity = 1
	return (
        <>
            {objects.map(object => (
                <Shapes
                    key={`${object.position.x},${object.position.y},${object.position.z},${Color},${opacity}`}
                    shape={object.shape} 
                    position={object.position}
                    color={object.color}
                    opacity={opacity}
                />
            ))}
        </>
	)
};

export default Minecraft