import { CartesianCoordinate } from "../../../interfaces/cartesianCoordinate";
import Color from "../../../interfaces/Color";
import * as THREE from 'three'
import { shapeComponentProps } from "./Shape";
import { Edges } from "@react-three/drei";


interface CubeFaceProps{
	position: THREE.Vector3,
	rotation: THREE.Euler,
	color: THREE.Color,
	opacity?: number 
}

const CubeFace = ({ 
	position, 
	rotation, 
	color,
	opacity = 1
}: CubeFaceProps) => {// Optional: Add texture
	return (
		<mesh position={position} rotation={rotation}>
			<planeGeometry attach="geometry" args={[1, 1]}/>
			{opacity === 1 && (
				<Edges linewidth={1} threshold={15} color={color} />
			)}
			<meshStandardMaterial attach="material" color={color}  transparent={opacity !== 1} opacity={opacity}/>
		</mesh>
	);
};

const Cube = ({position, color, opacity = 1} : shapeComponentProps) => {
	const cellSize = 1
	const borderThickness = 0.05

	const cubeColor =  new THREE.Color(color.hex)
	return (
		<mesh position={[
			position.x * (cellSize + borderThickness), 
			position.y + position.y * borderThickness, 
			position.z * (cellSize + borderThickness)
		]}>
			{/* Front */}
			<CubeFace 
				position={new THREE.Vector3(0, 0, 0.5)} 
				rotation={new THREE.Euler(0, 0, 0)} 
				color={cubeColor} 
				opacity={opacity}
			/>
			{/* Back */}
			<CubeFace 
				position={new THREE.Vector3(0, 0, -0.5)} 
				rotation={new THREE.Euler(0, Math.PI, 0)} 
				color={cubeColor} 
				opacity={opacity}
			/>
			{/* Top */}
			<CubeFace 
				position={new THREE.Vector3(0, 0.5, 0)} 
				rotation={new THREE.Euler(-Math.PI / 2, 0, 0)} 
				color={cubeColor} 
				opacity={opacity}
			/>
			{/* Bottom */}
			<CubeFace 
				position={new THREE.Vector3(0, -0.5, 0)} 
				rotation={new THREE.Euler(Math.PI / 2, 0, 0)} 
				color={cubeColor} 
				opacity={opacity}
			/>
			{/* Right */}
			<CubeFace 
				position={new THREE.Vector3(0.5, 0, 0)} 
				rotation={new THREE.Euler(0, Math.PI / 2, 0)} 
				color={cubeColor} 
				opacity={opacity}
			/>
			{/* Left */}
			<CubeFace 
				position={new THREE.Vector3(-0.5, 0, 0)} 
				rotation={new THREE.Euler(0, -Math.PI / 2, 0)} 
				color={cubeColor} 
				opacity={opacity}
			/>
		</mesh>
	)
};

export default Cube